    public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    next mapEntityToDataSource(_entityCtx, _dataSourceCtx);

    switch (_dataSourceCtx.name())
    {
        case dataEntityDataSourceStr(PurchPurchaseAgreementHeaderV2Entity, PurchAgreementHeader):

            PurchAgreementHeader purchAgreementHeader = _dataSourceCtx.getBuffer();

            ETGACFParameters parameters = ETGACFParameters::find();

            if (parameters.EnableDMSIntegration == NoYes::Yes &&
                parameters.EnablePurchaseAgreementWF == NoYes::No)
            {
                purchAgreementHeader.WorkflowStatus_PSN = PurchAgreementWorkflowStatus::Approved;
                this.AgreementWorkflowStatus = PurchAgreementWorkflowStatus::Approved;
            }

            break;
    }
}
